st_L(head); for (i = 1, j = 0; i &lt;= 8; i++, j++) //注意这里i从1开始， ListInsert_L(head, i, A[j]); //将数据依次放入 Search_L(head); printf(&quot;%d&quot;, Search_L(head));&#125;

